import React from 'react';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';
import { formatChartTime } from '../utils/time';
import { useTheme } from '../context/ThemeContext';

const CustomTooltip = ({ active, payload, label, isDark }) => {
  if (active && payload && payload.length) {
    return (
      <div style={{
        background: isDark ? '#1c2128' : '#ffffff',
        border: `1px solid ${isDark ? '#30363d' : '#e5e7eb'}`,
        borderRadius: '10px',
        padding: '6px 10px',
        fontSize: '12px',
        boxShadow: isDark ? '0 4px 16px rgba(0,0,0,0.5)' : '0 4px 16px rgba(0,0,0,0.08)',
      }}>
        <p style={{ color: isDark ? '#8b949e' : '#6b7280', marginBottom: '2px' }}>{label}</p>
        <p style={{ color: isDark ? '#56d364' : '#16a34a', fontWeight: 600 }}>{payload[0].value}ms</p>
      </div>
    );
  }
  return null;
};

export default function LatencyChart({ data }) {
  const { isDark } = useTheme();

  const chartData = data.map(p => ({
    time: formatChartTime(p.checkedAt),
    latency: p.latencyMs >= 0 ? p.latencyMs : null,
  }));

  const strokeColor  = isDark ? '#2ea043' : '#16a34a';
  const gradientStop = isDark ? '#2ea043' : '#22c55e';
  const gridColor    = isDark ? '#21262d' : '#f3f4f6';
  const axisColor    = isDark ? '#6e7681' : '#9ca3af';
  const axisLine     = isDark ? '#30363d' : '#e5e7eb';

  return (
    <ResponsiveContainer width="100%" height={200}>
      <AreaChart data={chartData} margin={{ top: 4, right: 4, left: 0, bottom: 0 }}>
        <defs>
          <linearGradient id="latGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%"   stopColor={gradientStop} stopOpacity={0.25} />
            <stop offset="100%" stopColor={gradientStop} stopOpacity={0} />
          </linearGradient>
        </defs>
        <CartesianGrid strokeDasharray="3 3" stroke={gridColor} vertical={false} />
        <XAxis dataKey="time" tick={{ fontSize: 10, fill: axisColor }} interval="preserveStartEnd" axisLine={{ stroke: axisLine }} tickLine={false} />
        <YAxis unit="ms" tick={{ fontSize: 10, fill: axisColor }} axisLine={false} tickLine={false} width={44} />
        <Tooltip content={<CustomTooltip isDark={isDark} />} />
        <Area
          type="monotone" dataKey="latency"
          stroke={strokeColor} strokeWidth={2}
          fill="url(#latGrad)"
          dot={false} connectNulls={false}
          activeDot={{ r: 4, fill: strokeColor, stroke: isDark ? '#161b22' : '#ffffff', strokeWidth: 2 }}
        />
      </AreaChart>
    </ResponsiveContainer>
  );
}
